*�����������������7//pt prefix for points attributes
//prim prefix for prims attributes
//vert prefix for prims attributes

//i prefix for input attributes

void main() {
	const uint id = TDIndex();
	if(id >= TDNumElements())
		return;

	vec3 primCenter = vec3(0);

	for(int i = 0; i< TDInputNumVertsPerPrim(); i++)
	{
		uint vertId = TDInputPrimVertsStartIndex() + i;
		uint pointId = TDInputPointIndex(vertId);
		primCenter += TDInPoint_P(0, pointId);
	}

	primCenter /= TDInputNumVertsPerPrim();

	oTDPrim_NumVertsPerPrim[TDInputPrimIndex()] = TDInputNumVertsPerPrim();
	oTDPrim_VertStart[TDInputPrimIndex()] = TDInputVertsStartIndex();

	for(int i = 0; i< TDInputNumVertsPerPrim(); i++)
	{
		uint vertId = TDInputPrimVertsStartIndex() + i;
		uint pointId = TDInputPointIndex(vertId);

		vec2 noise = TDInPrim_Noise(0, TDInputPrimIndex());

		float scale = TDRemap(noise.y,0,1,0.5,1);
		vec3 translate = TDRemap(noise.y,0,1,-0.1,0.1) * TDInPrim_N(0, TDInputPrimIndex());

		oTDPoint_P[pointId] = (TDInPoint_P(0, pointId) - primCenter) * uScale * scale + primCenter + translate;

		oTDVert_Tex[vertId] = TDInVert_Tex(0, vertId) + vec3(uUVTranslate,0,0);
	}


	vec4 color = vec4(1);

	if(TDInputPrimIndex() < 80)
	{
		color.rgb = vec3(1,.2,.2);
	}
	else
	{
		color.rgb = vec3(.2,1,.2);
	}

	oTDPrim_Color[TDInputPrimIndex()] = color;

}

